1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	type Step = QuoteStep;
14	
15	interface Scenario {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Step[];
18	}
19	
20	const BASE_PREMIUM: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	  moonstone: 25,
27	};
28	
29	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
30	const BLOCK_SIZE = 3;
31	const BLOCK_PREMIUM = 60;
32	
33	const FIRST_INSURANCE_SURCHARGE = 0.1;
34	const CURSE_SURCHARGE = 0.5;
35	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
36	const HIGH_ENCHANTMENT_THRESHOLD = 5;
37	const LOYALTY_DISCOUNT = 0.2;
38	const LOYALTY_THRESHOLD_YEARS = 2;
39	const PROCESSING_FEE = 5;
40	
41	// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
42	// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
43	const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));
44	
45	// A block applies only to a group of exactly BLOCK_SIZE alike components,
46	// priced at BLOCK_PREMIUM; any other count is priced individually.
47	const componentBasePremium = (count: number, perComponent: number): number => {
48	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
49	  return count * perComponent;
50	};
51	
52	const sum = (amounts: number[]): number => amounts.reduce((acc, amount) => acc + amount, 0);
53	
54	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
55	const isMainItem = (item: Item): boolean => !isComponent(item);
56	
57	const countByType = (items: Item[]): Record<string, number> => {
58	  const counts: Record<string, number> = {};
59	  for (const item of items) {
60	    counts[item.type] = (counts[item.type] ?? 0) + 1;
61	  }
62	  return counts;
63	};
64	
65	// A surcharge rate is an additive percentage applied on top of a base premium.
66	const applySurcharge = (base: number, rate: number): number => base * (1 + rate);
67	
68	const surchargeWhen = (applies: boolean, rate: number): number => (applies ? rate : 0);
69	
70	// Item-specific surcharges are additive percentages of the item's base premium.
71	// First insurance applies to every item; the others only when their condition holds.
72	const itemSurchargeRate = (item: Item): number =>
73	  sum([
74	    FIRST_INSURANCE_SURCHARGE,
75	    surchargeWhen(item.cursed === true, CURSE_SURCHARGE),
76	    surchargeWhen((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, HIGH_ENCHANTMENT_SURCHARGE),
77	  ]);
78	
79	const mainItemPremium = (item: Item): number =>
80	  applySurcharge(BASE_PREMIUM[item.type], itemSurchargeRate(item));
81	
82	const componentGroupBases = (items: Item[]): number[] =>
83	  Object.entries(countByType(items.filter(isComponent))).map(([type, count]) =>
84	    componentBasePremium(count, BASE_PREMIUM[type]),
85	  );
86	
87	// Sum of item base premiums with block pricing but no surcharges; the basis
88	// for policy-wide modifiers (loyalty, follow-up).
89	const policyBasePremium = (items: Item[]): number =>
90	  sum(items.filter(isMainItem).map((item) => BASE_PREMIUM[item.type])) +
91	  sum(componentGroupBases(items));
92	
93	// Sum of item premiums including item-specific surcharges (curse, high
94	// enchantment, first insurance).
95	const itemsPremium = (items: Item[]): number => {
96	  const mainItemsPremium = sum(items.filter(isMainItem).map(mainItemPremium));
97	  const componentsPremium = sum(
98	    componentGroupBases(items).map((base) => applySurcharge(base, FIRST_INSURANCE_SURCHARGE)),
99	  );
100	  return mainItemsPremium + componentsPremium;
101	};
102	
103	const loyaltyDiscount = (yearsWithMHPCO: number, policyBase: number): number =>
104	  yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT * policyBase : 0;
105	
106	const quotePremium = (items: Item[], yearsWithMHPCO: number): number => {
107	  const surcharged = itemsPremium(items);
108	  const discount = loyaltyDiscount(yearsWithMHPCO, policyBasePremium(items));
109	  return roundPremiumUp(surcharged - discount + PROCESSING_FEE);
110	};
111	
112	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
113	  const { yearsWithMHPCO } = scenario.customer;
114	  const results = scenario.steps.map((step) => ({
115	    premium: quotePremium(step.items, yearsWithMHPCO),
116	  }));
117	  return { results };
118	};
